def _printable(ch: str) -> str:
    if ch == "\n":
        return "\\n"
    if ch == "\t":
        return "\\t"
    if ch == "\r":
        return "\\r"
    if ch == " ":
        return "\\s"
    return ch


def tokenize(text: str) -> tuple[list[Token], list[LexError]]:
    """Analiza *text* y retorna (tokens, errors)."""
    tokens: list[Token] = []
    errors: list[LexError] = []

    pos = 0
    line = 1
    col = 1

    while pos < len(text):
        state = _START
        last_accept_pos = -1
        last_accept_label: str | None = None
        current = pos
        token_line = line
        token_col = col

        while current < len(text):
            ch = text[current]
            state_str = str(state)
            next_state = _TABLE.get(state_str, {}).get(ch)
            if next_state is None:
                break
            state = next_state
            current += 1

            state_key = str(state)
            if state_key in _ACCEPT:
                last_accept_pos = current
                last_accept_label = _ACCEPT[state_key]

        if last_accept_label is not None and last_accept_pos > pos:
            lexeme = text[pos:last_accept_pos]
            if last_accept_label != "__SKIP__":
                tokens.append(Token(
                    type=last_accept_label,
                    lexeme=lexeme,
                    line=token_line,
                    col=token_col,
                ))
            for ch in lexeme:
                if ch == "\n":
                    line += 1
                    col = 1
                else:
                    col += 1
            pos = last_accept_pos
        else:
            bad_char = text[pos]
            errors.append(LexError(
                char=bad_char,
                line=line,
                col=col,
                message=f"Error léxico en línea {line}, columna {col}: carácter inesperado '{_printable(bad_char)}'",
            ))
            if bad_char == "\n":
                line += 1
                col = 1
            else:
                col += 1
            pos += 1

    return tokens, errors


# ---- Trailer del archivo .yal ----
# (vacío)
# ---- Fin trailer ----


def main() -> None:
    if len(sys.argv) < 2:
        print("Uso: python {sys.argv[0]} <archivo_entrada>")
        sys.exit(1)

    input_path = sys.argv[1]
    with open(input_path, encoding="utf-8") as f:
        text = f.read()

    tokens, errors = tokenize(text)

    for token in tokens:
        print(token)

    if errors:
        print()
        for error in errors:
            print(error.message)
        sys.exit(1)


if __name__ == "__main__":
    main()
